#include <stdio.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long N, U;
        scanf("%lld %lld", &N, &U);
        printf("%lld\n", N - U);
    }
    return 0;
}

